INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (4, "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 24015, "カオリ（サマー）", 0.0, 0.0, 10021, 4, 1, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (1, "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 24016, "カオリ（サマー）", 4.0, 0.0, 10021, 4, 2, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (4, "マジムンだらけで目が回るさ～！\nふらふらさ～！", 24017, "カオリ（サマー）", 0.0, 0.0, 10021, 4, 3, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (2, "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 24018, "カオリ（サマー）", 5.2, 0.0, 10021, 1, 4, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (6, "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 24019, "カオリ（サマー）", 4.2, 0.0, 10021, 5, 5, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (2, "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 24020, "カオリ（サマー）", 0.0, 0.0, 10021, 2, 6, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (6, "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 24021, "カオリ（サマー）", 6.4, 0.0, 10021, 1, 7, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (2, "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 24022, "カオリ（サマー）", 0.0, 0.0, 10021, 2, 8, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (3, "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 24023, "カオリ（サマー）", 10.08, 0.0, 10021, 6, 9, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (2, "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 24024, "カオリ（サマー）", 5.0, 0.0, 10021, 1, 10, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (2, "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 24025, "カオリ（サマー）", 0.0, 0.0, 10021, 2, 11, 110501, "2019/07/31 12:00:00", 24, "2030/12/17 14:59:59", 0.0);
